import type {
  Edge,
  EdgeTypes,
  Node,
  NodeTypes,
  ReactFlowProps,
} from "@xyflow/react";
import type { ComponentType, ReactNode } from "react";
import type { CanvasEdgeAnchorResolver } from "./canvas.edge-anchors";

/** Body content for {@link CanvasPanel}; receives the selected React Flow node. */
export interface CanvasPanelBodyProps {
  node: Node;
}

/** Host-controlled panel tab selection (typically backed by `nuqs` in the Next app). */
export interface CanvasPanelTabSync {
  /** Persist tab changes (`useQueryState` setter or equivalent). */
  setTabValue: (value: string) => unknown;
  /** Current Radix Tabs value — equals the active tab's {@link CanvasPanelTab.name}. */
  tabValue: string;
}

/**
 * One tab in {@link CanvasMeta.panelTabs}.
 * Tab `name` doubles as the Radix value and URL query param — must be unique within a list.
 */
export type CanvasPanelTab =
  | {
      name: string;
      component: ReactNode;
      render?: never;
    }
  | {
      name: string;
      component?: never;
      render: (panel: CanvasPanelBodyProps) => ReactNode;
    };

export type CanvasPanelComponent = ComponentType<CanvasPanelBodyProps>;

/**
 * Panel body components keyed by React Flow node `type` string — use the same keys as
 * {@link CanvasMeta.nodeTypes} so selection shows the matching panel.
 */
export type CanvasPanelTypes = Partial<Record<string, CanvasPanelComponent>>;

/** Props forwarded to `<ReactFlow />`; canvas owns nodes/edges/types/change handlers. */
export type CanvasReactFlowProps = Omit<
  ReactFlowProps<Node, Edge>,
  | "children"
  | "defaultEdges"
  | "defaultNodes"
  | "edgeTypes"
  | "edges"
  | "nodeTypes"
  | "nodes"
  | "onEdgesChange"
  | "onNodesChange"
>;

export interface CanvasState {
  edges: Edge[];
  nodes: Node[];
  selectedEdge: Edge | null;
  selectedNode: Node | null;
}

export type CanvasSelectedNode = CanvasState["selectedNode"];
export type CanvasSelectedEdge = CanvasState["selectedEdge"];

export interface CanvasActions {
  fitView: () => void;
  onPanelClose: () => void;
}

export interface CanvasMeta {
  /**
   * Optional render-layer edge anchor resolver. When provided, edges with missing endpoint nodes
   * are skipped and resolved pairs are applied as React Flow source/target handles.
   */
  edgeAnchorResolver?: CanvasEdgeAnchorResolver;
  edgeTypes?: EdgeTypes;
  nodeTypes?: NodeTypes;
  /**
   * Controls the one-shot fit-to-view that runs when a canvas opens.
   */
  openingFitView?: {
    key?: number | string;
  };
  /**
   * Syncs multi-tab panels to host state / URL (typically backed by `nuqs`).
   * Omit for uncontrolled default tab (first tab's `name`).
   */
  panelTabSync?: CanvasPanelTabSync;
  /**
   * Tabbed panel bodies per node `type`. When the selected type entry is non-empty, it replaces
   * {@link CanvasMeta.panelTypes} for that type (Vercel-style tabs in {@link CanvasPanel}).
   */
  panelTabs?: Partial<Record<string, CanvasPanelTab[]>>;
  panelTypes?: CanvasPanelTypes;
  reactFlowProps?: CanvasReactFlowProps;
}

export interface CanvasContextValue {
  actions: CanvasActions;
  meta: CanvasMeta;
  state: CanvasState;
}

export interface CanvasPanelProps {
  children?: ReactNode;
  className?: string;
}

import { createContext } from "react";
import type { CanvasContextValue } from "./canvas.types";

export const CanvasContext = createContext<CanvasContextValue | null>(null);

"use client";

import { use } from "react";
import { CanvasContext } from "./canvas.context";

export function useCanvas() {
  const ctx = use(CanvasContext);
  if (!ctx) {
    throw new Error("useCanvas must be used inside Canvas.Root");
  }
  return ctx;
}

"use client";

import type { ReactNode } from "react";
import { useMemo } from "react";
import { CanvasContext } from "./canvas.context";
import type {
  CanvasActions,
  CanvasContextValue,
  CanvasMeta,
  CanvasState,
} from "./canvas.types";

export function CanvasProvider({
  actions,
  children,
  meta,
  state,
}: {
  actions?: Partial<CanvasActions>;
  children: ReactNode;
  meta?: CanvasMeta;
  state: CanvasState;
}) {
  const value = useMemo<CanvasContextValue>(
    () => ({
      actions: {
        fitView: actions?.fitView ?? (() => undefined),
        onPanelClose: actions?.onPanelClose ?? (() => undefined),
      },
      meta: meta ?? {},
      state,
    }),
    [actions?.fitView, actions?.onPanelClose, meta, state]
  );

  return <CanvasContext value={value}>{children}</CanvasContext>;
}

"use client";

import { cn } from "@workspace/ui/lib/utils";
import { Button } from "../button";

export function CanvasErrorFallback({
  error,
  reset,
  className,
}: {
  error: Error & { digest?: string };
  reset: () => void;
  /** Merged with default layout; omit for full-viewport route errors. */
  className?: string;
}) {
  return (
    <div
      className={cn(
        "flex flex-col items-center justify-center gap-4 p-6 text-center",
        className ?? "h-dvh"
      )}
    >
      <h1 className="font-medium text-lg">Canvas failed to load</h1>
      <p className="max-w-md text-muted-foreground text-sm">{error.message}</p>
      <Button onClick={reset}>Try again</Button>
    </div>
  );
}

.canvas-surface {
  position: absolute;
  inset: 0;
  overflow: hidden;
  background-color: var(--color-canvas-surface);
  background-image: radial-gradient(
    ellipse 83.7% 93.3% at 50% 50%,
    color-mix(in oklab, var(--color-canvas-glow) 22%, transparent) 0%,
    transparent 70%
  );
}

.canvas-surface > .react-flow {
  width: 100%;
  height: 100%;
  background: transparent;
}

.react-flow__pane.draggable,
.react-flow__pane.dragging {
  cursor: default;
}

.canvas-panel {
  border-left: 1px solid var(--color-border);
}

/* Unmarked handles are decorative; declare data-side to opt into visibility. */
.canvas-surface .react-flow__handle:not([data-side]) {
  top: auto;
  bottom: auto;
  width: 0;
  height: 0;
  opacity: 0;
}

import type { Edge, Node } from "@xyflow/react";
import type { CanvasNodeConnectionSide } from "../canvas-node/canvas-node.types";

export interface CanvasEdgeAnchorPair {
  sourceSide: CanvasNodeConnectionSide;
  targetSide: CanvasNodeConnectionSide;
}

export interface CanvasEdgeAnchorResolverInput {
  dragging: boolean;
  edge: Edge;
  previousPair?: CanvasEdgeAnchorPair;
  sourceNode: Node;
  targetNode: Node;
}

export type CanvasEdgeAnchorResolver = (
  input: CanvasEdgeAnchorResolverInput
) => CanvasEdgeAnchorPair | null | undefined;

export interface ResolveCanvasEdgeAnchorsOptions {
  dragging: boolean;
  edges: readonly Edge[];
  nodes: readonly Node[];
  previousPairs: ReadonlyMap<string, CanvasEdgeAnchorPair>;
  resolver: CanvasEdgeAnchorResolver;
}

export interface ResolveCanvasEdgeAnchorsResult {
  anchorPairs: Map<string, CanvasEdgeAnchorPair>;
  edges: Edge[];
}

export function resolveCanvasEdgeAnchors({
  dragging,
  edges,
  nodes,
  previousPairs,
  resolver,
}: ResolveCanvasEdgeAnchorsOptions): ResolveCanvasEdgeAnchorsResult {
  const nodeById = new Map(nodes.map((node) => [node.id, node]));
  const anchorPairs = new Map<string, CanvasEdgeAnchorPair>();
  const resolvedEdges: Edge[] = [];

  for (const edge of edges) {
    const sourceNode = nodeById.get(edge.source);
    const targetNode = nodeById.get(edge.target);
    if (sourceNode === undefined || targetNode === undefined) {
      continue;
    }

    const pair = resolver({
      dragging,
      edge,
      previousPair: previousPairs.get(edge.id),
      sourceNode,
      targetNode,
    });
    if (pair == null) {
      continue;
    }

    anchorPairs.set(edge.id, pair);
    resolvedEdges.push({
      ...edge,
      sourceHandle: pair.sourceSide,
      targetHandle: pair.targetSide,
    });
  }

  return { anchorPairs, edges: resolvedEdges };
}

"use client";

import {
  createContext,
  type ReactNode,
  useContext,
  useLayoutEffect,
  useMemo,
  useState,
} from "react";

interface CanvasUpperRightContextValue {
  content: ReactNode;
  setUpperRight: (content: ReactNode) => void;
}

const CanvasUpperRightContext =
  createContext<CanvasUpperRightContextValue | null>(null);

/**
 * Supplies the slot used by {@link CanvasUpperRight} and
 * {@link CanvasUpperRightAnchor} / {@link useCanvasUpperRightContent}.
 * Rendered inside {@link Canvas.Flow} only.
 */
export function CanvasUpperRightProvider({
  children,
}: {
  children: ReactNode;
}) {
  const [upperRight, setUpperRight] = useState<ReactNode>(null);
  const value = useMemo(
    () => ({
      content: upperRight,
      setUpperRight,
    }),
    [upperRight]
  );

  return (
    <CanvasUpperRightContext.Provider value={value}>
      {children}
    </CanvasUpperRightContext.Provider>
  );
}

CanvasUpperRightProvider.displayName = "CanvasUpperRightProvider";

/** Renders registered content at the top-right of the canvas viewport. */
export function CanvasUpperRightAnchor() {
  const ctx = useContext(CanvasUpperRightContext);
  if (ctx?.content == null) {
    return null;
  }
  return (
    <div
      className="pointer-events-auto absolute top-2 right-2 z-10 flex items-center gap-2"
      data-slot="canvas-upper-right"
    >
      {ctx.content}
    </div>
  );
}

CanvasUpperRightAnchor.displayName = "CanvasUpperRightAnchor";

export function useCanvasUpperRightContent(): ReactNode | null {
  return useContext(CanvasUpperRightContext)?.content ?? null;
}

export interface CanvasUpperRightProps {
  children: ReactNode;
}

/**
 * Register UI for the canvas upper-right slot (and the side panel header, when
 * open). Must be a descendant of `Canvas.Flow`. Renders nothing itself.
 */
export function CanvasUpperRight({ children }: CanvasUpperRightProps) {
  const ctx = useContext(CanvasUpperRightContext);
  if (ctx == null) {
    throw new Error("Canvas.UpperRight must be used inside Canvas.Flow");
  }
  const { setUpperRight } = ctx;
  useLayoutEffect(() => {
    setUpperRight(children);
    return () => {
      setUpperRight(null);
    };
  }, [children, setUpperRight]);
  return null;
}

CanvasUpperRight.displayName = "Canvas.UpperRight";

"use client";

import "@xyflow/react/dist/base.css";
import "@xyflow/react/dist/style.css";
import "./canvas.css";

import {
  Background,
  BackgroundVariant,
  ConnectionMode,
  type Edge,
  type Node,
  ReactFlow,
  ReactFlowProvider,
  useEdgesState,
  useNodesInitialized,
  useNodesState,
  useReactFlow,
  useStore,
} from "@xyflow/react";
import type { ReactNode } from "react";
import { useEffect, useLayoutEffect, useMemo, useRef } from "react";
import {
  type CanvasEdgeAnchorPair,
  resolveCanvasEdgeAnchors,
} from "./canvas.edge-anchors";
import { CanvasPanel } from "./canvas.panel";
import { CanvasProvider } from "./canvas.provider";
import type { CanvasActions, CanvasReactFlowProps } from "./canvas.types";
import {
  CanvasUpperRight,
  CanvasUpperRightAnchor,
  CanvasUpperRightProvider,
} from "./canvas.upper-right";
import { useCanvas } from "./canvas.use";

export interface CanvasFlowProps {
  children?: ReactNode;
}

export interface CanvasRootProps {
  actions?: Partial<CanvasActions>;
  children?: ReactNode;
  meta?: Parameters<typeof CanvasProvider>[0]["meta"];
  state: Parameters<typeof CanvasProvider>[0]["state"];
}

const CANVAS_DEFAULT_EDGE_STYLE = {
  stroke: "var(--color-blue-400)",
  strokeDasharray: "6 6",
};
const DEFAULT_OPENING_FIT_KEY = "__default__";
const OPENING_FIT_ANIMATION_MS = 300;
const OPENING_FIT_SETTLE_MS = 150;

function mergeNodes(prev: Node[], next: Node[]): Node[] {
  const prevById = new Map(prev.map((n) => [n.id, n]));
  const merged = next.map((incoming) => {
    const existing = prevById.get(incoming.id);
    if (existing) {
      return {
        ...incoming,
        data: mergeNodeData(existing, incoming),
        position: existing.position,
      };
    }
    return incoming;
  });
  return merged;
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
  return value != null && typeof value === "object"
    ? (value as Record<string, unknown>)
    : undefined;
}

function nodeLayoutExpanded(node: Node): boolean | undefined {
  const data = asRecord(node.data);
  const layout = asRecord(data?.layout);
  return typeof layout?.expanded === "boolean" ? layout.expanded : undefined;
}

function mergeNodeData(existing: Node, incoming: Node): Node["data"] {
  const existingExpanded = nodeLayoutExpanded(existing);
  if (existingExpanded === undefined) {
    return incoming.data;
  }

  const incomingData = asRecord(incoming.data) ?? {};
  const incomingLayout = asRecord(incomingData.layout) ?? {};
  return {
    ...incomingData,
    layout: {
      ...incomingLayout,
      expanded: existingExpanded,
    },
  };
}

function CanvasFlow({ children }: CanvasFlowProps) {
  const { meta, state } = useCanvas();
  const [nodes, setNodes, onNodesChange] = useNodesState(state.nodes);
  const [edges, setEdges, onEdgesChange] = useEdgesState(state.edges);
  const { fitView, viewportInitialized } = useReactFlow<Node, Edge>();
  const nodesInitialized = useNodesInitialized();
  const flowHeight = useStore((store) => store.height);
  const flowWidth = useStore((store) => store.width);
  const initializedRef = useRef(false);
  const openingFitAppliedKeyRef = useRef<number | string | null>(null);
  const edgeAnchorPairsRef = useRef(new Map<string, CanvasEdgeAnchorPair>());

  useLayoutEffect(() => {
    if (initializedRef.current) {
      setNodes((prev) => mergeNodes(prev, state.nodes));
    } else {
      initializedRef.current = true;
      setNodes(state.nodes);
    }
  }, [setNodes, state.nodes]);

  useLayoutEffect(() => {
    setEdges(state.edges);
  }, [setEdges, state.edges]);

  const edgesWithSelectionStyle = useMemo((): Edge[] => {
    const selected = state.selectedEdge;
    if (selected == null) {
      return edges;
    }
    return edges.map((edge) => {
      if (edge.id !== selected.id) {
        return edge;
      }
      const prev =
        edge.style && typeof edge.style === "object" ? edge.style : {};
      return {
        ...edge,
        style: {
          ...CANVAS_DEFAULT_EDGE_STYLE,
          ...prev,
          stroke: CANVAS_DEFAULT_EDGE_STYLE.stroke,
        },
      };
    });
  }, [edges, state.selectedEdge]);
  const edgeAnchorResolver = meta.edgeAnchorResolver;
  const nodeDragging = nodes.some((node) => node.dragging === true);
  const edgeAnchorResolution = useMemo(() => {
    if (edgeAnchorResolver == null) {
      return {
        anchorPairs: edgeAnchorPairsRef.current,
        edges: edgesWithSelectionStyle,
      };
    }

    return resolveCanvasEdgeAnchors({
      dragging: nodeDragging,
      edges: edgesWithSelectionStyle,
      nodes,
      previousPairs: edgeAnchorPairsRef.current,
      resolver: edgeAnchorResolver,
    });
  }, [edgeAnchorResolver, edgesWithSelectionStyle, nodeDragging, nodes]);

  useEffect(() => {
    if (edgeAnchorResolver == null) {
      edgeAnchorPairsRef.current.clear();
      return;
    }

    edgeAnchorPairsRef.current = edgeAnchorResolution.anchorPairs;
  }, [edgeAnchorResolver, edgeAnchorResolution.anchorPairs]);

  const userReactFlowProps = meta.reactFlowProps ?? {};
  const userDefaultEdgeOptions = userReactFlowProps.defaultEdgeOptions;
  const userConnectionLineStyle = userReactFlowProps.connectionLineStyle;
  const openingFitViewOptions = userReactFlowProps.fitViewOptions;
  const shouldFitOpeningView = userReactFlowProps.fitView !== false;
  const passThrough: CanvasReactFlowProps = {
    connectionMode: ConnectionMode.Loose,
    maxZoom: 1.2,
    minZoom: 0.2,
    panOnDrag: true,
    panOnScroll: true,
    proOptions: { hideAttribution: true },
    selectNodesOnDrag: false,
    snapGrid: [16, 16],
    snapToGrid: true,
    ...userReactFlowProps,
    fitView: false,
    connectionLineStyle: {
      ...CANVAS_DEFAULT_EDGE_STYLE,
      ...(userConnectionLineStyle ?? {}),
    },
    defaultEdgeOptions: {
      ...userDefaultEdgeOptions,
      style: {
        ...CANVAS_DEFAULT_EDGE_STYLE,
        ...(userDefaultEdgeOptions?.style ?? {}),
      },
    },
  };
  const openingFitKey = meta.openingFitView?.key ?? DEFAULT_OPENING_FIT_KEY;
  const nodeCount = nodes.length;

  useEffect(() => {
    if (
      openingFitAppliedKeyRef.current === openingFitKey ||
      !shouldFitOpeningView ||
      !viewportInitialized ||
      !nodesInitialized ||
      flowHeight <= 0 ||
      flowWidth <= 0 ||
      nodeCount === 0
    ) {
      return;
    }

    let firstFrame = 0;
    let secondFrame = 0;
    const settleTimer = window.setTimeout(() => {
      firstFrame = window.requestAnimationFrame(() => {
        secondFrame = window.requestAnimationFrame(() => {
          openingFitAppliedKeyRef.current = openingFitKey;
          fitView({
            duration: OPENING_FIT_ANIMATION_MS,
            ...openingFitViewOptions,
          });
        });
      });
    }, OPENING_FIT_SETTLE_MS);

    return () => {
      window.clearTimeout(settleTimer);
      window.cancelAnimationFrame(firstFrame);
      window.cancelAnimationFrame(secondFrame);
    };
  }, [
    fitView,
    flowHeight,
    flowWidth,
    nodeCount,
    nodesInitialized,
    openingFitKey,
    openingFitViewOptions,
    shouldFitOpeningView,
    viewportInitialized,
  ]);

  return (
    <CanvasUpperRightProvider>
      <div className="relative h-full min-h-0 w-full min-w-0">
        <CanvasUpperRightAnchor />
        <div className="canvas-surface">
          <ReactFlow
            {...passThrough}
            edges={edgeAnchorResolution.edges}
            edgeTypes={meta.edgeTypes}
            nodes={nodes}
            nodeTypes={meta.nodeTypes}
            onEdgesChange={onEdgesChange}
            onNodesChange={onNodesChange}
          >
            <Background
              color="var(--color-canvas-dot)"
              gap={32}
              size={1}
              variant={BackgroundVariant.Dots}
            />
          </ReactFlow>
        </div>
        {children}
      </div>
    </CanvasUpperRightProvider>
  );
}

function CanvasRoot({ actions, children, meta, state }: CanvasRootProps) {
  return (
    <CanvasProvider actions={actions} meta={meta} state={state}>
      {children}
    </CanvasProvider>
  );
}

function CanvasSurface({ children }: CanvasFlowProps) {
  return (
    <div className="h-full min-h-0 w-full min-w-0">
      <ReactFlowProvider>
        <CanvasFlow>{children}</CanvasFlow>
      </ReactFlowProvider>
    </div>
  );
}

export const Canvas = Object.assign(CanvasSurface, {
  Flow: CanvasSurface,
  Panel: CanvasPanel,
  Root: CanvasRoot,
  UpperRight: CanvasUpperRight,
});

export type CanvasProps = CanvasRootProps;
